package genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan.mapper.MaintenancePlanMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan.repository.MaintenancePlanRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenancePlanService { private final MaintenancePlanRepository repository; private final MaintenancePlanMapper mapper; public MaintenancePlanService(MaintenancePlanRepository repository,MaintenancePlanMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenancePlanResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenancePlanResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenancePlan", String.valueOf(id))); } public MaintenancePlanResponse create(MaintenancePlanUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenancePlanResponse update(UUID id,MaintenancePlanUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenancePlan", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenancePlan", String.valueOf(id)); } }
